def now():
    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")


def today():
    return date.today().isoformat()


def load_json(path, default):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return default


def save_json(path, data):
    tmp = path + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    os.replace(tmp, path)


def D(value, fallback="0"):
    try:
        return Decimal(str(value if value not in (None, "") else fallback).replace(",", ".").strip())
    except (InvalidOperation, ValueError):
        return Decimal(fallback)



def fmt(value, asset=""):
    value = D(value)
    if asset == "LTC":
        if value == 0:
            number = "0.00"
        else:
            out = value.quantize(Decimal("0.000001"), rounding=ROUND_DOWN)
            number = format(out, "f").rstrip("0").rstrip(".")
            if "." not in number:
                number += ".00"
            else:
                decimals = len(number.split(".", 1)[1])
                if decimals < 2:
                    number += "0" * (2 - decimals)
    else:
        out = value.quantize(Decimal("0.01"), rounding=ROUND_DOWN)
        number = format(out, ".2f")
    return f"{number} {asset}".strip()


def normalize_amount(value, asset):
    precision = Decimal("0.000001") if asset == "LTC" else Decimal("0.01")
    return D(value).quantize(precision, rounding=ROUND_DOWN)


def parse_amount_input(value, asset):
    raw = str(value or "").strip().upper()
    raw = raw.replace(asset, "").replace("₺", "").replace(" ", "")
    if not raw:
        raise InvalidOperation
    if "," in raw and "." in raw:
        if raw.rfind(",") > raw.rfind("."):
            raw = raw.replace(".", "").replace(",", ".")
        else:
            raw = raw.replace(",", "")
    else:
        raw = raw.replace(",", ".")
    return normalize_amount(Decimal(raw), asset)

def h(value):
    return escape(str(value if value is not None else ""), quote=True)


