def resolve_emoji_id(icon_key):
    """Her kullanıcı mesajında uygun custom emoji kullanılmasını garanti eder."""
    requested = str(settings.get(icon_key or "", "")).strip()
    if requested:
        return requested
    return str(settings.get("icon_info", DEFAULT_SETTINGS["icon_info"])).strip()


def infer_icon_key(text):
    low = str(text).lower()
    if "redded" in low or "iptal" in low:
        return "icon_rejected"
    if "tamamlandı" in low or "başarıyla" in low:
        return "icon_completed"
    if "işleme alınd" in low or "kontrol aşaması" in low or "işleniyor" in low:
        return "icon_processing"
    if "bekliyor" in low or "bildiriminiz alındı" in low or "talebiniz oluşturuldu" in low:
        return "icon_pending"
    if "pin" in low or "güvenlik" in low or "oturum" in low:
        return "icon_security"
    if "dönüştür" in low or "dönüşüm" in low:
        return "icon_convert"
    if "çekim" in low or "para çek" in low:
        return "icon_withdraw"
    if "yatır" in low or "bakiye yükle" in low or "ödeme" in low:
        return "icon_deposit"
    if "geçmiş" in low or "işlem no" in low or "işlem kaydı" in low:
        return "icon_history"
    if "destek" in low:
        return "icon_support"
    if "cüzdan" in low or "bakiye" in low:
        return "icon_wallet"
    return "icon_info"


def send(chat_id, text, keyboard=None, icon_key=None, auto_icon=True):
    raw_text = str(text)
    key = icon_key or (infer_icon_key(raw_text) if auto_icon else "")
    emoji_id = resolve_emoji_id(key) if key else resolve_emoji_id("icon_info")
    fallback = ICON_FALLBACKS.get(key, "ℹ️")
    payload_text = raw_text
    entities = []
    if key:
        payload_text = f"{fallback} {raw_text}"
        if emoji_id:
            entities.append({
                "type": "custom_emoji", "offset": 0,
                "length": utf16_len(fallback), "custom_emoji_id": emoji_id,
            })
    payload = {"chat_id": chat_id, "text": payload_text}
    if entities:
        payload["entities"] = entities
    if keyboard:
        payload["reply_markup"] = keyboard
    result = api("sendMessage", payload)
    if entities and result.get("ok") is False:
        payload.pop("entities", None)
        return api("sendMessage", payload)
    return result


def rich_lines(items):
    parts = []
    entities = []
    for item in items:
        if item is None:
            parts.append("")
            continue
        if isinstance(item, str):
            parts.append(item)
            continue
        line, icon_key, fallback = item
        prefix = fallback or ICON_FALLBACKS.get(icon_key, "•")
        offset = utf16_len("\n".join(parts)) + (1 if parts else 0)
        rendered = f"{prefix} {line}"
        emoji_id = resolve_emoji_id(icon_key)
        if emoji_id:
            entities.append({
                "type": "custom_emoji", "offset": offset,
                "length": utf16_len(prefix), "custom_emoji_id": emoji_id,
            })
        parts.append(rendered)
    return "\n".join(parts), entities


def send_rich(chat_id, items, keyboard=None):
    message_text, entities = rich_lines(items)
    if not entities:
        fallback = ICON_FALLBACKS["icon_info"]
        message_text = f"{fallback} {message_text}"
        entities = [{
            "type": "custom_emoji",
            "offset": 0,
            "length": utf16_len(fallback),
            "custom_emoji_id": resolve_emoji_id("icon_info"),
        }]
    payload = {"chat_id": chat_id, "text": message_text}
    if entities:
        payload["entities"] = entities
    if keyboard:
        payload["reply_markup"] = keyboard
    result = api("sendMessage", payload)
    if entities and result.get("ok") is False:
        payload.pop("entities", None)
        return api("sendMessage", payload)
    return result


def send_qr(chat_id, content, caption="", icon_key="icon_wallet"):
    qr = qrcode.QRCode(
        version=None,
        error_correction=qrcode.constants.ERROR_CORRECT_H,
        box_size=12,
        border=4,
    )
    qr.add_data(content)
    qr.make(fit=True)
    img = qr.make_image(fill_color="#07111f", back_color="white").convert("RGBA")
    try:
        logo = Image.open(io.BytesIO(base64.b64decode(ZAQEL_LOGO_BASE64))).convert("RGBA")
        logo.thumbnail((img.width // 4, img.height // 4), Image.Resampling.LANCZOS)
        pad = 12
        plate = Image.new("RGBA", (logo.width + pad * 2, logo.height + pad * 2), "white")
        plate.alpha_composite(logo, (pad, pad))
        img.alpha_composite(plate, ((img.width - plate.width) // 2, (img.height - plate.height) // 2))
    except Exception as exc:
        print("QR LOGO ERROR:", exc)
    buf = io.BytesIO()
    img.convert("RGB").save(buf, format="PNG", optimize=True)
    buf.seek(0)
    fallback = ICON_FALLBACKS.get(icon_key, "💼")
    emoji_id = resolve_emoji_id(icon_key)
    final_caption = f"{fallback} {caption}" if caption else fallback
    data = {"chat_id": str(chat_id), "caption": final_caption}
    if emoji_id:
        data["caption_entities"] = json.dumps([{
            "type": "custom_emoji", "offset": 0,
            "length": utf16_len(fallback), "custom_emoji_id": emoji_id,
        }])
    result = api("sendPhoto", data, {"photo": ("zaqelv2-qr.png", buf, "image/png")})
    if emoji_id and result.get("ok") is False:
        buf.seek(0)
        data.pop("caption_entities", None)
        return api("sendPhoto", data, {"photo": ("zaqelv2-qr.png", buf, "image/png")})
    return result

