def asset_keyboard(prefix, assets, exclude=None):
    rows = []
    for asset in assets:
        if asset != exclude:
            rows.append([inline_button(asset, f"{prefix}:{asset}", f"icon_{asset}")])
    rows.append([inline_button("İptal", "cancel", "icon_rejected")])
    return {"inline_keyboard": rows}


