def active_balances(uid):
    return [a for a in ASSETS if balance(uid, a) > 0]



def request_summary(rid):
    r = requests_db.get(str(rid), {})
    if not r:
        return "İşlem bulunamadı."
    type_name = {"deposit": "Bakiye Yükleme", "withdraw": "Para Çekme", "convert": "Dönüştürme"}.get(r.get("type"), r.get("type"))
    lines = [f"İşlem #{rid}", f"{type_name} · {status_label(r.get('status'))}", ""]
    if r.get("type") == "deposit":
        lines += [f"Yatırılan: {fmt(r.get('amount'), r.get('asset'))}", f"Bakiyeye yansıyacak: {fmt(r.get('net_amount'), r.get('asset'))}"]
        if r.get("asset") == "TL":
            lines += [f"Gönderen: {r.get('sender_name','-')}", f"Ödeme notu: {r.get('tx_note','-')}"]
        else:
            lines += [f"Ağ: {r.get('network','-')}"]
    elif r.get("type") == "withdraw":
        lines += [f"Çekim tutarı: {fmt(r.get('amount'), r.get('asset'))}", f"Kesilecek komisyon: {fmt(r.get('fee'), r.get('asset'))}", f"Net gönderilecek: {fmt(r.get('net_amount'), r.get('asset'))}"]
        if r.get("asset") == "TL":
            lines += [f"Banka: {r.get('bank_name','')}", f"IBAN: {r.get('iban','')}", f"Alıcı: {r.get('name','')}"]
        else:
            lines += [f"Hedef adres: {r.get('address','')}"]
    elif r.get("type") == "convert":
        lines += [f"Dönüştürülen: {fmt(r.get('from_amount'), r.get('from_asset'))}", f"TL karşılığı: {fmt(r.get('tl_value'), 'TL')}", f"Kesilecek komisyon: {fmt(r.get('fee'), r.get('to_asset'))}", f"Hesaba geçecek: {fmt(r.get('net_to_amount'), r.get('to_asset'))}"]
    lines += ["", f"Oluşturulma: {r.get('created_at','')}"]
    if r.get("updated_at") and r.get("updated_at") != r.get("created_at"):
        lines.append(f"Son güncelleme: {r.get('updated_at')}")
    return "\n".join(lines)


