def execute_conversion(uid, state):
    if state.get("flow") != "convert" or not state.get("amount"):
        send(uid, messages["session_expired"] if "session_expired" in messages else "İşlem oturumu bulunamadı. Lütfen yeniden başlayınız.", reply_keyboard(), "icon_rejected")
        return
    from_asset = state["from_asset"]
    amount = normalize_amount(state["amount"], from_asset)
    if amount <= 0 or amount > normalize_amount(balance(uid, from_asset), from_asset):
        send(uid, f"Kullanılabilir bakiyeniz bu işlem için yeterli değil.\nMevcut bakiye: {fmt(balance(uid, from_asset), from_asset)}", reply_keyboard(), "icon_rejected")
        return
    rid = new_request(uid, "convert", {
        "from_asset": from_asset,
        "to_asset": state["to_asset"],
        "from_amount": str(amount),
        "tl_value": state["tl_value"],
        "fee": state["fee"],
        "net_to_amount": state["net_amount"],
        "second_confirmation": True,
    })
    try:
        change_balance(uid, from_asset, -amount, "convert_out", rid)
        change_balance(uid, state["to_asset"], D(state["net_amount"]), "convert_in", rid)
    except ValueError:
        requests_db.pop(rid, None)
        save_json(FILES["requests"], requests_db)
        send(uid, messages["insufficient_balance"], reply_keyboard(), "icon_rejected")
        return
    requests_db[rid]["status"] = "completed"
    requests_db[rid]["completed_at"] = now()
    requests_db[rid]["updated_at"] = now()
    save_json(FILES["requests"], requests_db)
    user_state.pop(uid, None)
    send_status_update(uid, rid, "completed")


def process_amount(uid, chat_id, state, amount):
    flow = state.get("flow")
    asset = state.get("asset") or state.get("from_asset")
    amount = normalize_amount(amount, asset)
    available = normalize_amount(balance(uid, asset), asset)
    if amount <= 0:
        send(chat_id, "Geçerli bir tutar giriniz.", icon_key="icon_rejected")
        return False
    if flow in ("withdraw", "convert") and amount > available:
        send(chat_id, f"Yetersiz bakiye.\nKullanılabilir: {fmt(available, asset)}", icon_key="icon_rejected")
        return False
    if amount < min_amount(flow, asset):
        send(chat_id, f"Minimum işlem tutarı: {fmt(min_amount(flow, asset), asset)}", icon_key="icon_info")
        return False
    state["amount"] = str(amount)

    if flow == "deposit":
        fee = fee_amount(amount, fee_percent("deposit", asset, uid))
        net = amount - fee
        state.update({"fee": str(fee), "net_amount": str(net)})
        if asset == "TL":
            card = (
                "TL Bakiye Yükleme Bilgileri\n\n"
                f"Banka: {settings['bank_name']}\n"
                f"IBAN: {settings['iban']}\n"
                f"Alıcı: {settings['iban_owner']}\n\n"
                f"Yatırılacak Tutar: {fmt(amount, 'TL')}\n"
                f"Kesilecek Komisyon: {fmt(fee, 'TL')}\n"
                f"Bakiyeye Yansıyacak: {fmt(net, 'TL')}\n\n"
                f"{messages['iban_warning']}"
            )
            kb = {"inline_keyboard": [
                [copy_button("IBAN'ı Kopyala", settings["iban"], "icon_deposit")],
                [inline_button("Ödemeyi Yaptım", "deposit_sent", "icon_deposit")],
                [inline_button("İptal", "cancel", "icon_rejected")],
            ]}
            send(chat_id, card, kb, "icon_deposit")
        else:
            address = settings.get(f"wallet_{asset}", "")
            network = settings.get(f"network_{asset}", asset)
            state.update({"network": network, "address": address})
            card = (
                f"{asset} Bakiye Yükleme Bilgileri\n\n"
                f"Ağ: {network}\n"
                f"Yatırılacak Tutar: {fmt(amount, asset)}\n"
                f"Kesilecek Komisyon: {fmt(fee, asset)}\n"
                f"Bakiyeye Yansıyacak: {fmt(net, asset)}\n\n"
                f"Yatırma Adresi:\n{address}\n\n"
                f"{messages['deposit_crypto_intro']}"
            )
            kb = {"inline_keyboard": [
                [copy_button("Adresi Kopyala", address, f"icon_{asset}"), inline_button("QR Göster", "deposit_qr", f"icon_{asset}")],
                [inline_button("Gönderimi Bildir", "deposit_sent", "icon_deposit")],
                [inline_button("İptal", "cancel", "icon_rejected")],
            ]}
            send(chat_id, card, kb, f"icon_{asset}")
        state["step"] = "waiting_sent"
        return True

    if flow == "withdraw":
        if withdrawn_today(uid, asset) + amount > daily_limit(asset) > 0:
            remaining = daily_limit(asset) - withdrawn_today(uid, asset)
            send(chat_id, f"Günlük çekim limitiniz aşılıyor.\nKalan limit: {fmt(max(remaining, Decimal('0')), asset)}", icon_key="icon_rejected")
            return False
        fee = fee_amount(amount, fee_percent("withdraw", asset, uid))
        net = amount - fee
        if net <= 0:
            send(chat_id, "Komisyon sonrası gönderilecek tutar sıfırdan büyük olmalıdır.", icon_key="icon_rejected")
            return False
        state.update({"fee": str(fee), "net_amount": str(net)})
        if asset == "TL":
            state["step"] = "bank_name"
            send(chat_id, "Paranın gönderileceği banka adını giriniz.", icon_key="icon_withdraw")
        else:
            favs = [f for f in users[uid].get("favorites", []) if f.get("asset") == asset]
            if favs:
                rows = [[inline_button(f["label"], f"favorite_use:{i}", f"icon_{asset}")] for i, f in enumerate(users[uid]["favorites"]) if f.get("asset") == asset]
                rows.append([inline_button("Yeni adres gir", "favorite_use:new", f"icon_{asset}")])
                rows.append([inline_button("İptal", "cancel", "icon_rejected")])
                send(chat_id, "Çekim adresini seçiniz.", {"inline_keyboard": rows}, f"icon_{asset}")
                state["step"] = "address_choice"
            else:
                state["step"] = "address"
                send(chat_id, "Alıcı cüzdan adresini giriniz.", icon_key=f"icon_{asset}")
        return True

    if flow == "convert":
        to_asset = state["to_asset"]
        tl_value = amount * rate(asset)
        gross = tl_value / rate(to_asset)
        fee = fee_amount(gross, fee_percent("convert", uid=uid))
        net = gross - fee
        if net <= 0:
            send(chat_id, "Komisyon sonrası alınacak tutar sıfırdan büyük olmalıdır.", icon_key="icon_rejected")
            return False
        state.update({"tl_value": str(tl_value), "gross_to": str(gross), "fee": str(fee), "net_amount": str(net)})
        state["preview"] = (
            "Dönüşüm Özeti\n\n"
            f"Dönüştürülecek: {fmt(amount, asset)}\n"
            f"TL karşılığı: {fmt(tl_value, 'TL')}\n"
            f"Kesilecek komisyon: {fmt(fee, to_asset)}\n"
            f"Hesaba geçecek: {fmt(net, to_asset)}"
        )
        require_pin(uid, state)
        return True
    return False



def finalize_withdraw(uid, state):
    if state.get("flow") != "withdraw" or not state.get("amount"):
        send(uid, "İşlem oturumu bulunamadı. Lütfen yeniden başlayınız.", reply_keyboard(), "icon_rejected")
        return
    asset = state["asset"]
    amount = normalize_amount(state["amount"], asset)
    if amount > normalize_amount(balance(uid, asset), asset):
        send(uid, messages["insufficient_balance"], reply_keyboard(), "icon_rejected")
        return
    rid = new_request(uid, "withdraw", {
        "asset": asset, "amount": str(amount), "fee": state["fee"], "net_amount": state["net_amount"],
        "bank_name": state.get("bank_name", ""), "iban": state.get("iban", ""), "name": state.get("name", ""), "address": state.get("address", ""),
        "second_confirmation": True,
    })
    try:
        change_balance(uid, asset, -amount, "withdraw_hold_available", rid)
        change_pending(uid, asset, amount, "withdraw_hold_pending", rid)
    except ValueError:
        requests_db.pop(rid, None)
        save_json(FILES["requests"], requests_db)
        send(uid, messages["insufficient_balance"], reply_keyboard(), "icon_rejected")
        return
    user_state.pop(uid, None)
    send(uid, messages["request_created"], reply_keyboard(), "icon_pending")
    send_request_detail(uid, rid, "Çekim Talebi Özeti")
    if ADMIN_CHAT_ID:
        send(ADMIN_CHAT_ID, "Yeni çekim talebi\n\n" + request_summary(rid), icon_key="icon_withdraw")


def handle_text(chat_id, username, text):
    uid = str(chat_id)
    get_user(chat_id, username)
    if text == "/start" or text == "Ana Menü":
        start_user(chat_id, username)
        return
    if not user_allowed(chat_id):
        return
    if text == "Cüzdanım":
        send_wallet(chat_id)
        return
    if text == "Bakiye Yükle":
        begin_deposit(chat_id)
        return
    if text == "Para Çek":
        begin_withdraw(chat_id)
        return
    if text == "Dönüştür":
        begin_convert(chat_id)
        return
    if text == "İşlem Geçmişi":
        show_history(chat_id)
        return
    if text == "Güvenlik":
        show_security(chat_id)
        return
    if text == "Favori Adresler":
        favs = users[uid].get("favorites", [])
        if not favs:
            send(chat_id, "Kayıtlı favori adresiniz bulunmuyor.", {"inline_keyboard": [[inline_button("Yeni Adres Ekle", "favorite:add", "icon_wallet")]]}, "icon_wallet")
        else:
            lines = ["Favori Cüzdan Adresleri"] + [f"{i+1}. {f['label']} · {f['asset']}\n{f['address']}" for i, f in enumerate(favs)]
            send(chat_id, "\n\n".join(lines), {"inline_keyboard": [[inline_button("Yeni Adres Ekle", "favorite:add", "icon_wallet")]]}, "icon_wallet")
        return
    if text == "Destek":
        send(chat_id, messages["support"], reply_keyboard(), "icon_support")
        return

    state = user_state.get(uid)
    if not state:
        send(chat_id, "Menüden bir işlem seçiniz.", reply_keyboard(), "icon_info")
        return
    flow, step = state.get("flow"), state.get("step")

    if step == "set_pin":
        pin = text.strip()
        if not pin.isdigit() or not 4 <= len(pin) <= 6:
            send(chat_id, "PIN 4-6 haneli rakamlardan oluşmalıdır.", icon_key="icon_rejected")
            return
        state["new_pin"] = pin
        state["step"] = "confirm_new_pin"
        send(chat_id, "Yeni PIN'inizi tekrar giriniz.", icon_key="icon_security")
        return

    if step == "confirm_new_pin":
        if text.strip() != state.get("new_pin"):
            user_state.pop(uid, None)
            send(chat_id, "PIN'ler eşleşmedi. İşlemi yeniden başlatınız.", reply_keyboard(), "icon_rejected")
            return
        changing = state.get("changing_pin", False)
        next_step = state.pop("after_pin_setup", None)
        users[uid]["pin_hash"] = hash_pin(text.strip())
        users[uid]["session_version"] = int(users[uid].get("session_version", 1)) + 1
        users[uid]["last_pin_change"] = now()
        users[uid]["sessions"] = {"telegram": {"created_at": now(), "last_seen": now(), "active": True, "version": users[uid]["session_version"]}}
        users[uid]["pin_failed_attempts"] = 0
        save_json(FILES["users"], users)
        add_security_event(uid, "pin_changed" if changing else "pin_created", "Tüm eski oturumlar geçersiz kılındı")
        state.pop("new_pin", None)
        state.pop("changing_pin", None)
        if next_step:
            send(chat_id, messages["pin_saved"], icon_key="icon_completed")
            show_second_confirmation(uid, state)
        else:
            user_state.pop(uid, None)
            send(chat_id, messages["pin_changed"] if changing else messages["pin_saved"], reply_keyboard(), "icon_completed")
        return

    if step == "old_pin":
        if hash_pin(text.strip()) != users[uid].get("pin_hash"):
            users[uid]["pin_failed_attempts"] = int(users[uid].get("pin_failed_attempts", 0)) + 1
            save_json(FILES["users"], users)
            if users[uid]["pin_failed_attempts"] >= 3:
                users[uid]["withdraw_locked"] = True
                save_json(FILES["users"], users)
                add_security_event(uid, "pin_lock", "3 hatalı PIN denemesi")
                send(chat_id, "Üç hatalı PIN denemesi nedeniyle çekimleriniz geçici olarak kilitlendi.", icon_key="icon_rejected")
            else:
                send(chat_id, messages["pin_wrong"], icon_key="icon_rejected")
            return
        users[uid]["pin_failed_attempts"] = 0
        save_json(FILES["users"], users)
        state["step"] = "set_pin"
        state["changing_pin"] = True
        send(chat_id, "Yeni işlem PIN'inizi giriniz.", icon_key="icon_security")
        return

    if step == "pin":
        if hash_pin(text.strip()) != users[uid].get("pin_hash"):
            users[uid]["pin_failed_attempts"] = int(users[uid].get("pin_failed_attempts", 0)) + 1
            save_json(FILES["users"], users)
            if users[uid]["pin_failed_attempts"] >= 3:
                users[uid]["withdraw_locked"] = True
                save_json(FILES["users"], users)
                add_security_event(uid, "pin_lock", "3 hatalı PIN denemesi")
                send(chat_id, "Üç hatalı PIN denemesi nedeniyle çekimleriniz geçici olarak kilitlendi.", icon_key="icon_rejected")
            else:
                send(chat_id, messages["pin_wrong"], icon_key="icon_rejected")
            return
        users[uid]["pin_failed_attempts"] = 0
        save_json(FILES["users"], users)
        show_second_confirmation(uid, state)
        return

    if step == "amount":
        asset = state.get("asset") or state.get("from_asset")
        try:
            amount = parse_amount_input(text, asset)
        except (InvalidOperation, ValueError):
            send(chat_id, "Geçerli bir tutar giriniz. Örnek: 0.110101", icon_key="icon_rejected")
            return
        process_amount(uid, chat_id, state, amount)
        return

    if flow == "deposit" and step == "sender_name":
        state["sender_name"] = text.strip()
        state["step"] = "tx_note"
        send(chat_id, "Ödeme açıklamasına yazdığınız bilgiyi giriniz. Paylaşmak istemiyorsanız YOK yazabilirsiniz.", icon_key="icon_deposit")
        return
    if flow == "deposit" and step == "tx_note":
        data = {
            "asset": state["asset"], "amount": state["amount"], "fee": state["fee"],
            "net_amount": state["net_amount"], "sender_name": state.get("sender_name", ""),
            "tx_note": text.strip(),
        }
        rid = new_request(uid, "deposit", data)
        change_pending(uid, state["asset"], D(state["net_amount"]), "deposit_pending", rid)
        user_state.pop(uid, None)
        send_deposit_created(uid, rid)
        if ADMIN_CHAT_ID:
            send(ADMIN_CHAT_ID, "Yeni TL bakiye yükleme bildirimi\n\n" + request_summary(rid), icon_key="icon_deposit")
        return
    if flow == "withdraw" and step == "bank_name":
        state["bank_name"] = text.strip()
        state["step"] = "iban"
        send(chat_id, "IBAN bilginizi giriniz.", icon_key="icon_withdraw")
        return
    if flow == "withdraw" and step == "iban":
        state["iban"] = text.replace(" ", "").upper()
        state["step"] = "name"
        send(chat_id, "Hesap sahibinin ad ve soyadını giriniz.", icon_key="icon_withdraw")
        return
    if flow == "withdraw" and step == "name":
        state["name"] = text.strip()
        state["preview"] = (
            "Çekim Özeti\n\n"
            f"Mevcut bakiye: {fmt(balance(uid, state['asset']), state['asset'])}\n"
            f"Çekim tutarı: {fmt(state['amount'], state['asset'])}\n"
            f"Kesilecek komisyon: {fmt(state['fee'], state['asset'])}\n"
            f"Net gönderilecek: {fmt(state['net_amount'], state['asset'])}\n"
            f"IBAN: {state['iban']}\n"
            f"Ad Soyad: {state['name']}"
        )
        require_pin(uid, state)
        return
    if flow == "withdraw" and step == "address":
        state["address"] = text.strip()
        state["preview"] = (
            "Çekim Özeti\n\n"
            f"Mevcut bakiye: {fmt(balance(uid, state['asset']), state['asset'])}\n"
            f"Çekim tutarı: {fmt(state['amount'], state['asset'])}\n"
            f"Kesilecek komisyon: {fmt(state['fee'], state['asset'])}\n"
            f"Net gönderilecek: {fmt(state['net_amount'], state['asset'])}\n"
            f"Hedef adres: {state['address']}"
        )
        require_pin(uid, state)
        return
    if flow == "favorite_add" and step == "label":
        state["label"] = text.strip()
        state["step"] = "address"
        send(chat_id, "Cüzdan adresini giriniz.", icon_key=f"icon_{state['asset']}")
        return
    if flow == "favorite_add" and step == "address":
        users[uid]["favorites"].append({"label": state["label"], "asset": state["asset"], "address": text.strip(), "created_at": now()})
        save_json(FILES["users"], users)
        user_state.pop(uid, None)
        send(chat_id, "Favori adres kaydedildi.", reply_keyboard(), "icon_completed")
        return


def handle_callback(chat_id, username, data, cb_id):
    answer(cb_id)
    uid = str(chat_id)
    get_user(chat_id, username)
    if data == "cancel":
        user_state.pop(uid, None)
        send(chat_id, messages["request_cancelled"], reply_keyboard(), "icon_rejected")
        return
    if data.startswith("detail:"):
        rid = data.split(":", 1)[1]
        if requests_db.get(rid, {}).get("user_id") == uid:
            send_request_detail(chat_id, rid, "ZaqelV2 İşlem Kaydı", {"inline_keyboard": [[inline_button("İşlem Detayını Yenile", f"detail:{rid}", "icon_history")]]})
        return
    if data.startswith("deposit_asset:"):
        asset = data.split(":", 1)[1]
        user_state[uid] = {"flow": "deposit", "step": "amount", "asset": asset}
        send(chat_id, f"{asset} için yatırmak istediğiniz tutarı giriniz.\nMinimum yükleme: {fmt(min_amount('deposit', asset), asset)}", icon_key=f"icon_{asset}")
        return
    if data == "deposit_qr":
        state = user_state.get(uid, {})
        if state.get("flow") != "deposit" or not state.get("address"):
            send(chat_id, "QR bilgisi bulunamadı. Lütfen işlemi yeniden başlatınız.", icon_key="icon_rejected")
            return
        send_qr(chat_id, state["address"], f"{state['asset']} Yatırma Adresi · {state.get('network', state['asset'])}", f"icon_{state['asset']}")
        return
    if data == "deposit_sent":
        state = user_state.get(uid, {})
        if state.get("flow") != "deposit" or not state.get("amount"):
            send(chat_id, "İşlem oturumu bulunamadı. Lütfen yeniden başlayınız.", icon_key="icon_rejected")
            return
        if state.get("asset") == "TL":
            state["step"] = "sender_name"
            send(chat_id, "Ödemeyi gerçekleştiren kişinin ad ve soyadını giriniz.", icon_key="icon_deposit")
        else:
            req_data = {
                "asset": state["asset"], "amount": state["amount"], "fee": state["fee"],
                "net_amount": state["net_amount"], "network": state.get("network", ""),
            }
            rid = new_request(uid, "deposit", req_data)
            change_pending(uid, state["asset"], D(state["net_amount"]), "deposit_pending", rid)
            user_state.pop(uid, None)
            send_deposit_created(uid, rid)
            if ADMIN_CHAT_ID:
                send(ADMIN_CHAT_ID, "Yeni kripto bakiye yükleme bildirimi\n\n" + request_summary(rid), icon_key="icon_deposit")
        return
    if data.startswith("withdraw_asset:"):
        asset = data.split(":", 1)[1]
        available = normalize_amount(balance(uid, asset), asset)
        if available <= 0:
            send(chat_id, messages["no_balance"], icon_key="icon_rejected")
            return
        user_state[uid] = {"flow": "withdraw", "step": "amount", "asset": asset}
        kb = {"inline_keyboard": [
            [inline_button("Tüm Bakiyeyi Çek", f"withdraw_all:{asset}", "icon_withdraw")],
            [inline_button("İptal", "cancel", "icon_rejected")],
        ]}
        send(chat_id, f"Çekilebilir bakiye: {fmt(available, asset)}\nMinimum çekim: {fmt(min_amount('withdraw', asset), asset)}\n\nÇekmek istediğiniz tutarı giriniz veya tüm bakiyeyi seçiniz.", kb, f"icon_{asset}")
        return
    if data.startswith("withdraw_all:"):
        asset = data.split(":", 1)[1]
        state = user_state.get(uid, {})
        if state.get("flow") != "withdraw" or state.get("asset") != asset:
            user_state[uid] = {"flow": "withdraw", "step": "amount", "asset": asset}
            state = user_state[uid]
        process_amount(uid, chat_id, state, normalize_amount(balance(uid, asset), asset))
        return
    if data.startswith("convert_from:"):
        asset = data.split(":", 1)[1]
        if balance(uid, asset) <= 0:
            send(chat_id, messages["no_balance"], icon_key="icon_rejected")
            return
        user_state[uid] = {"flow": "convert", "step": "to_asset", "from_asset": asset}
        send(chat_id, f"Dönüştürülebilir bakiye: {fmt(balance(uid, asset), asset)}", asset_keyboard("convert_to", ASSETS, asset), f"icon_{asset}")
        return
    if data.startswith("convert_to:"):
        to_asset = data.split(":", 1)[1]
        state = user_state.get(uid, {})
        if state.get("flow") != "convert" or not state.get("from_asset"):
            send(chat_id, "İşlem oturumu bulunamadı. Lütfen yeniden başlayınız.", icon_key="icon_rejected")
            return
        state.update({"to_asset": to_asset, "step": "amount"})
        source = state["from_asset"]
        send(chat_id, f"Kullanılabilir bakiye: {fmt(balance(uid, source), source)}\nMinimum dönüşüm: {fmt(min_amount('convert', source), source)}\n\nDönüştürülecek tutarı giriniz.", icon_key=f"icon_{source}")
        return
    if data == "second_confirm":
        state = user_state.get(uid, {})
        if state.get("step") != "second_confirm":
            send(chat_id, "Onay bekleyen bir işlem bulunamadı. Lütfen işlemi yeniden başlatınız.", reply_keyboard(), "icon_rejected")
            return
        if state.get("flow") == "withdraw":
            finalize_withdraw(uid, state)
        elif state.get("flow") == "convert":
            execute_conversion(uid, state)
        else:
            send(chat_id, "İşlem türü doğrulanamadı. Lütfen yeniden başlayınız.", reply_keyboard(), "icon_rejected")
        return
    if data == "favorite:add":
        user_state[uid] = {"flow": "favorite_add", "step": "asset"}
        send(chat_id, "Favori adresin para birimini seçiniz.", asset_keyboard("favorite_asset", CRYPTO_ASSETS), "icon_wallet")
        return
    if data.startswith("favorite_asset:"):
        user_state[uid] = {"flow": "favorite_add", "step": "label", "asset": data.split(":", 1)[1]}
        send(chat_id, "Bu adres için bir isim giriniz.", icon_key="icon_wallet")
        return
    if data.startswith("favorite_use:"):
        choice = data.split(":", 1)[1]
        state = user_state.get(uid, {})
        if choice == "new":
            state["step"] = "address"
            send(chat_id, "Alıcı cüzdan adresini giriniz.", icon_key=f"icon_{state.get('asset','USDT')}")
        else:
            fav = users[uid]["favorites"][int(choice)]
            state["address"] = fav["address"]
            state["preview"] = (
                "Çekim Özeti\n\n"
                f"Mevcut bakiye: {fmt(balance(uid, state['asset']), state['asset'])}\n"
                f"Çekim tutarı: {fmt(state['amount'], state['asset'])}\n"
                f"Kesilecek komisyon: {fmt(state['fee'], state['asset'])}\n"
                f"Net gönderilecek: {fmt(state['net_amount'], state['asset'])}\n"
                f"Hedef adres: {state['address']}"
            )
            require_pin(uid, state)
        return
    if data == "security:set_pin":
        if users[uid].get("pin_hash"):
            user_state[uid] = {"flow": "set_pin", "step": "old_pin"}
            send(chat_id, "Mevcut işlem PIN'inizi giriniz.", icon_key="icon_security")
        else:
            user_state[uid] = {"flow": "set_pin", "step": "set_pin"}
            send(chat_id, messages["pin_set_question"], icon_key="icon_security")
        return
    if data == "security:notifications":
        n = users[uid]["notifications"]
        kb = {"inline_keyboard": [
            [inline_button(f"İşlemler: {'Açık' if n['transactions'] else 'Kapalı'}", "notify:transactions", "icon_history")],
            [inline_button(f"Güvenlik: {'Açık' if n['security'] else 'Kapalı'}", "notify:security", "icon_security")],
            [inline_button(f"Duyurular: {'Açık' if n['announcements'] else 'Kapalı'}", "notify:announcements", "icon_info")],
        ]}
        send(chat_id, "Bildirim tercihlerinizi düzenleyiniz.", kb, "icon_security")
        return
    if data.startswith("notify:"):
        key = data.split(":", 1)[1]
        users[uid]["notifications"][key] = not users[uid]["notifications"].get(key, True)
        save_json(FILES["users"], users)
        send(chat_id, "Bildirim tercihi güncellendi.", icon_key="icon_completed")
        return
    if data == "security:logout_sessions":
        users[uid]["sessions"] = {"telegram": {"created_at": now(), "last_seen": now(), "active": True}}
        save_json(FILES["users"], users)
        send(chat_id, "Diğer oturum kayıtları kapatıldı.", icon_key="icon_completed")
        return

def bot_loop():
    global OFFSET
    while True:
        try:
            result = requests.get(f"https://api.telegram.org/bot{TOKEN}/getUpdates", params={"offset": OFFSET, "timeout": 25}, timeout=35).json()
            for update in result.get("result", []):
                OFFSET = update["update_id"] + 1
                if "message" in update:
                    m = update["message"]; chat_id = m["chat"]["id"]; username = m.get("from", {}).get("username", "unknown"); text = m.get("text", "")
                    ids = [str(e.get("custom_emoji_id")) for e in m.get("entities", []) if e.get("type") == "custom_emoji" and e.get("custom_emoji_id")]
                    if ids and str(chat_id) == str(ADMIN_CHAT_ID): send(chat_id, "\n".join(ids)); continue
                    handle_text(chat_id, username, text)
                elif "callback_query" in update:
                    c = update["callback_query"]; handle_callback(c["message"]["chat"]["id"], c.get("from", {}).get("username", "unknown"), c.get("data", ""), c["id"])
        except Exception as exc:
            print("BOT LOOP ERROR:", exc); time.sleep(5)


